class Solution:
    def numberOfSets(self, n, k):
        MOD = 10 ** 9 + 7
        m = n + k - 1
        r = 2 * k
        row = [0] * (r + 1)
        row[0] = 1
        for i in range(1, m + 1):
            upper = min(i, r)
            for j in range(upper, 0, -1):
                row[j] = (row[j] + row[j - 1]) % MOD
        return row[r] if r <= m else 0

