class Solution:
    def numberOfSets(self, n, k):
        MOD = 10 ** 9 + 7
        dp_done = [0] * (k + 1)
        dp_end = [0] * (k + 1)
        dp_done[0] = 1
        for _ in range(n):
            new_done = [0] * (k + 1)
            new_end = [0] * (k + 1)
            for j in range(k + 1):
                new_done[j] = (dp_done[j] + dp_end[j]) % MOD
            for j in range(1, k + 1):
                new_end[j] = (dp_end[j] + dp_done[j - 1] + dp_end[j - 1]) % MOD
            dp_done, dp_end = new_done, new_end
        return dp_done[k]

