var numberOfSets = function(n, k) {
    const MOD = 1000000007;
    let dpDone = new Array(k + 1).fill(0);
    let dpEnd = new Array(k + 1).fill(0);
    dpDone[0] = 1;
    for (let i = 0; i < n; i++) {
        const newDone = new Array(k + 1).fill(0);
        const newEnd = new Array(k + 1).fill(0);
        for (let j = 0; j <= k; j++) {
            newDone[j] = (dpDone[j] + dpEnd[j]) % MOD;
        }
        for (let j = 1; j <= k; j++) {
            newEnd[j] = (dpEnd[j] + dpDone[j - 1] + dpEnd[j - 1]) % MOD;
        }
        dpDone = newDone;
        dpEnd = newEnd;
    }
    return dpDone[k];
};
